 1	import React from 'react';
 2	
 3	import AlertStatusItem from '@kubevirt-utils/components/AlertsCard/AlertStatusItem';
 4	import { AlertType } from '@kubevirt-utils/components/AlertsCard/utils/types';
 5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 6	import {
 7	  AccordionContent,
 8	  AccordionItem,
 9	  AccordionToggle,
10	  Divider,
11	  Label,
12	} from '@patternfly/react-core';
13	
14	import './AlertsCard.scss';
15	
16	type AlertsCardAccordionItemProps = {
17	  alertOpen: AlertType;
18	  alerts: any;
19	  alertType: AlertType;
20	  handleDrawerToggleClick: (alertType: AlertType) => void;
21	};
22	
23	const AlertsCardAccordionItem: React.FC<AlertsCardAccordionItemProps> = ({
24	  alertOpen,
25	  alerts,
26	  alertType,
27	  handleDrawerToggleClick,
28	}) => {
29	  const { t } = useKubevirtTranslation();
30	
31	  const alertTitle = {
32	    [AlertType.critical]: t('Critical'),
33	    [AlertType.info]: t('Info'),
34	    [AlertType.warning]: t('Warnings'),
35	  };
36	
37	  return (
38	    <AccordionItem>
39	      <AccordionToggle
40	        onClick={() => {
41	          handleDrawerToggleClick(alertType);
42	        }}
43	        className="alerts-card__toggle--item"
44	        id={alertType}
45	
46	      >
47	        <div className="subtitle">
48	          <span className="subtitle-name">{alertTitle?.[alertType]}</span>
49	          <Label className="subtitle-label" isCompact>
50	            {alerts?.length || 0}
51	          </Label>
52	        </div>
53	      </AccordionToggle>
54	      <AccordionContent id={alertType} key={alertType}>
55	        <Divider />
56	        {alerts?.map((alert) => (
57	          <div className="content" key={alert?.key}>
58	            <AlertStatusItem alertDetails={alert} alertType={alertType} />
59	          </div>
60	        ))}
61	      </AccordionContent>
62	    </AccordionItem>
63	  );
64	};
65	
66	export default AlertsCardAccordionItem;

